Your task is to write a Jest test case that exposes a specific mutation in a JavaScript/TypeScript project.

MUTATION DETAILS
The mutation affects the following file:
pull.js
Here is the full content of that file (shown with a <PLACEHOLDER> marker):
'use strict'

module.exports = function pull (a) {
  var length = arguments.length
  if (typeof a === 'function' && a.length === 1) {
    var args = new Array(length)
    for(var i = 0; i < length; i++)
      args[i] = arguments[i]
    return function (read) {
      if (args == null) {
        throw new TypeError("partial sink should only be called once!")
      }

      // Grab the reference after the check, because it's always an array now
      // (engines like that kind of consistency).
      var ref = args
      args = null

      // Prioritize common case of small number of pulls.
      switch (length) {
      case 1: return pull(read, ref[0])
      case 2: return pull(read, ref[0], ref[1])
      case 3: return pull(read, ref[0], ref[1], ref[2])
         case 4:
<PLACEHOLDER>
        return pull.apply(null, ref)
      }
    }
  }

  var read = a

  if (read && typeof read.source === 'function') {
    read = read.source
  }

  for (var i = 1; i < length; i++) {
    var s = arguments[i]
    if (typeof s === 'function') {
      read = s(read)
    } else if (s && typeof s === 'object') {
      s.sink(read)
      read = s.source
    }
  }

  return read
}

In the original code, <PLACEHOLDER> has the value:

-         default:
-           ref.unshift(read)
-           return pull.apply(null, ref)
In the mutated code, <PLACEHOLDER> has the value:

+         default:


YOUR TASK
Write one Jest test file that:
    1. Passes when run against the original code.
    2. Fails when run against the mutated code.
    3. Tests the behavior of the mutated file in a way that reliably detects the mutation.
The test will be saved at the following path, relative to this test-generation project’s root:
llm-cache/anthropic_claude-sonnet-4.6/temp_0.5/withoutTests/cached/artifacts/pull-stream/attempt_1/pending_category/mutant-8ceacd5/testCase.test.ts

ALLOWED LIBRARIES
You may use:
    1. Any built-in Node.js modules (e.g., fs, path, crypto, etc.).

You may not use any other third-party libraries.

Looking at the mutation, the `default` case in the switch statement is being removed. This means that when `pull` is called with 5 or more arguments (length >= 5), the function won't properly unshift `read` into `ref` before calling `pull.apply(null, ref)`.

The original code for the `default` case:
```javascript
default:
  ref.unshift(read)
  return pull.apply(null, ref)
```

The mutated code removes the `default` case entirely, so when `length >= 5`, the `switch` falls through to the line `return pull.apply(null, ref)` without `read` being unshifted into `ref`.

Wait, let me re-read. The switch has cases 1, 2, 3, 4, and `default`. The mutation removes the `default` case but keeps `return pull.apply(null, ref)`. So for `length >= 5`, `read` won't be unshifted into `ref`, meaning the first argument to the recursive `pull.apply` call will be missing `read`.

Let me write a test that uses 5 or more pipeline stages to expose this:

```typescript
import pull from "../../../../../../../../../../../subject_repositories/pull-stream/pull.js"

describe("pull with 5+ arguments (partial sink default case)", () => {
  it("should correctly pipe through 5 pipeline stages", (done) => {
    // Create a source that produces values 1, 2, 3
    const source = (end: any, cb: Function) => {
      let i = 0;
      const values = [1, 2, 3];
      if (end) return cb(end);
      if (i >= values.length) return cb(true);
      // We need a stateful source
    };

    // Use a simpler approach with through streams
    const results: number[] = [];

    // Simple through function that adds 1
    const addOne = (read: Function) => (end: any, cb: Function) => {
      read(end, (end: any, data: number) => {
        if (end) return cb(end);
        cb(null, data + 1);
      });
    };

    // Simple values source
    let i = 0;
    const values = [1, 2, 3];
    const simpleSource = (end: any, cb: Function) => {
      if (end) return cb(end);
      if (i >= values.length) return cb(true);
      cb(null, values[i++]);
    };

    // Sink that collects results
    const collect = (read: Function) => {
      read(null, function next(end: any, data: number) {
        if (end === true) {
          expect(results).toEqual([6, 7, 8]);
          done();
          return;
        }
        if (end) { done(end); return; }
        results.push(data);
        read(null, next);
      });
    };

    // Use 5 arguments: source + 3 through + sink = 5 total
    pull(simpleSource, addOne, addOne, addOne, collect);
  });
});
```

